+				if (nextKey != Long.MAX_VALUE) {
+					acc.setField(0, orderToValueMapView.get(nextKey).get(0));
+					acc.setField(1, nextKey);
+				} else {
+					acc.setField(0, null);
+					acc.setField(1, null);
+				}
+			}
+		}
+	}
